const { CosmosClient } = require("@azure/cosmos");
const { app } = require("@azure/functions");

const cosmosClient = new CosmosClient(process.env.COSMOS_DB_CONNECTION_STRING);
const database = cosmosClient.database(process.env.DATABASE_NAME);
const container = database.container(process.env.CONTAINER_NAME);

app.timer('batchProcessor', {
    schedule: '0 */5 * * * *',
    handler: async function (context, myTimer) {
        context.log('Batch processing function started at:', new Date().toISOString());
        
        try {
            const batchSize = 1000;
            let continuationToken = null;
            let processedCount = 0;
            
            do {
                const query = `SELECT * FROM c OFFSET ${processedCount} LIMIT ${batchSize}`;
                const { resources, continuation } = await container.query(query, { 
                    continuation: continuationToken,
                    maxItemCount: batchSize
                }).fetchAll();
                
                if (resources.length === 0) {
                    break;
                }
                
                await processBatch(resources);
                processedCount += resources.length;
                continuationToken = continuation;
                
                context.log(`Processed batch: ${processedCount} items`);
                
                // Check if we're close to timeout (9 minutes to be safe)
                if (context.executionContext.remainingTimeInMillis < 60000) {
                    context.log('Approaching timeout, continuing in next execution');
                    break;
                }
                
            } while (continuationToken);
            
            context.log(`Batch processing completed. Total items processed: ${processedCount}`);
            
        } catch (error) {
            context.log.error('Error in batch processing:', error);
            throw error;
        }
    },
    options: {
        timeout: 600000,
        disableTimeout: true
    }
});

async function processBatch(items) {
    // Simulate processing logic
    const processedItems = items.map(item => {
        // Your processing logic here
        return {
            ...item,
            processedAt: new Date().toISOString(),
            status: 'processed'
        };
    });
    
    // Bulk write back to Cosmos DB
    const bulkOperations = processedItems.map(item => ({
        operationType: "Replace",
        resourceBody: item
    }));
    
    await container.batch(bulkOperations);
}